import{_ as a,o as i,c as l,ag as t}from"./chunks/framework.CTpQozEL.js";const d=JSON.parse('{"title":"macOS 로깅","description":"OpenClaw 로깅: 롤링 진단 파일 로그 + 통합 로그 개인 정보 플래그","frontmatter":{"title":"macOS 로깅","description":"OpenClaw 로깅: 롤링 진단 파일 로그 + 통합 로그 개인 정보 플래그"},"headers":[],"relativePath":"platforms/mac/logging.md","filePath":"platforms/mac/logging.md","lastUpdated":null}'),e={name:"platforms/mac/logging.md"};function n(p,s,o,r,h,g){return i(),l("div",null,[...s[0]||(s[0]=[t(`<h1 id="로깅-macos" tabindex="-1">로깅 (macOS) <a class="header-anchor" href="#로깅-macos" aria-label="Permalink to &quot;로깅 (macOS)&quot;">​</a></h1><h2 id="롤링-진단-파일-로그-debug-창" tabindex="-1">롤링 진단 파일 로그 (Debug 창) <a class="header-anchor" href="#롤링-진단-파일-로그-debug-창" aria-label="Permalink to &quot;롤링 진단 파일 로그 (Debug 창)&quot;">​</a></h2><p>OpenClaw는 macOS 앱 로그를 swift-log를 통해 라우팅하며 (기본값 통합 로깅), 내구성 있는 캡처가 필요할 때 로컬 회전 파일 로그를 디스크에 쓸 수 있습니다.</p><ul><li>상세도: <strong>Debug 창 → Logs → App logging → Verbosity</strong></li><li>활성화: <strong>Debug 창 → Logs → App logging → &quot;Write rolling diagnostics log (JSONL)&quot;</strong></li><li>위치: <code>~/Library/Logs/OpenClaw/diagnostics.jsonl</code> (자동으로 회전됨; 이전 파일에는 <code>.1</code>, <code>.2</code>, ...가 접미사로 붙음)</li><li>지우기: <strong>Debug 창 → Logs → App logging → &quot;Clear&quot;</strong></li></ul><p>참고:</p><ul><li>기본적으로 <strong>꺼져 있습니다</strong>. 활발하게 디버깅하는 동안에만 활성화하십시오.</li><li>파일을 민감한 것으로 취급하십시오. 검토 없이 공유하지 마십시오.</li></ul><h2 id="macos에서-통합-로깅-개인-데이터" tabindex="-1">macOS에서 통합 로깅 개인 데이터 <a class="header-anchor" href="#macos에서-통합-로깅-개인-데이터" aria-label="Permalink to &quot;macOS에서 통합 로깅 개인 데이터&quot;">​</a></h2><p>통합 로깅은 서브시스템이 <code>privacy -off</code>를 선택하지 않는 한 대부분의 페이로드를 수정합니다. macOS <a href="https://steipete.me/posts/2025/logging-privacy-shenanigans" target="_blank" rel="noreferrer">로깅 개인 정보 기이한 점</a> (2025)에 대한 Peter의 글에 따르면 이는 서브시스템 이름을 키로 하는 <code>/Library/Preferences/Logging/Subsystems/</code>의 plist로 제어됩니다. 새 로그 항목만 플래그를 선택하므로 문제를 재현하기 전에 활성화하십시오.</p><h2 id="openclaw에-대해-활성화-ai-openclaw" tabindex="-1">OpenClaw에 대해 활성화 (<code>ai.openclaw</code>) <a class="header-anchor" href="#openclaw에-대해-활성화-ai-openclaw" aria-label="Permalink to &quot;OpenClaw에 대해 활성화 (\`ai.openclaw\`)&quot;">​</a></h2><ul><li>plist를 임시 파일에 먼저 쓴 다음 루트로 원자적으로 설치합니다:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/ai.openclaw.plist</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;!DOCTYPE plist PUBLIC &quot;-//Apple//DTD PLIST 1.0//EN&quot; &quot;http://www.apple.com/DTDs/PropertyList-1.0.dtd&quot;&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;plist version=&quot;1.0&quot;&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;key&gt;DEFAULT-OPTIONS&lt;/key&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &lt;key&gt;Enable-Private-Data&lt;/key&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &lt;true/&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;/dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/plist&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 644</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/ai.openclaw.plist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Library/Preferences/Logging/Subsystems/ai.openclaw.plist</span></span></code></pre></div><ul><li>재부팅이 필요하지 않습니다. logd가 파일을 빠르게 인식하지만 새 로그 줄에만 개인 페이로드가 포함됩니다.</li><li>기존 도우미를 사용하여 풍부한 출력을 봅니다. 예: <code>./scripts/clawlog.sh --category WebChat --last 5m</code>.</li></ul><h2 id="디버깅-후-비활성화" tabindex="-1">디버깅 후 비활성화 <a class="header-anchor" href="#디버깅-후-비활성화" aria-label="Permalink to &quot;디버깅 후 비활성화&quot;">​</a></h2><ul><li>재정의 제거: <code>sudo rm /Library/Preferences/Logging/Subsystems/ai.openclaw.plist</code>.</li><li>선택적으로 <code>sudo log config --reload</code>를 실행하여 logd가 재정의를 즉시 삭제하도록 강제합니다.</li><li>이 표면에는 전화번호와 메시지 본문이 포함될 수 있습니다. 추가 세부 정보가 필요한 동안에만 plist를 유지하십시오.</li></ul>`,14)])])}const k=a(e,[["render",n]]);export{d as __pageData,k as default};
